transform.script:
const taskText = triggeringMessage.content?.text || '';
if (!taskText || !taskText.trim()) throw new Error('ISSUE_OPENED has no text content — nothing to review');

return {
  topic: 'CLUSTER_OPERATIONS',
  content: {
    text: '[CODE-REVIEW:BELL] Pass-through routing to bell tier',
    data: {
      operations: [
        {
          action: 'load_config',
          config: {
            base: 'code-review-workflow',
            params: {
              tier: 'bell',
              analyst_level: 'level2',
              validator_count: 1,
              max_iterations: 3,
              max_tokens: 100000,
              validator_level: 'level2',
              change_scope: 'PATCH',
              risk_domain: 'GENERAL',
              has_security_surface: false,
              has_test_changes: false,
              has_api_changes: false
            }
          }
        },
        {
          action: 'publish',
          topic: 'ISSUE_OPENED',
          content: { text: taskText },
          metadata: { _republished: true }
        }
      ]
    }
  }
};
